//vip.opstream11.com/share/ab59511d026575e380bffdf3e6ad451f","link_m3u8":"https://vip.opstream11.com/20220507/23664_9b260b80/index.m3u8"}]}],"time":"","description":"<p>Phim có tựa đề việt là Cuộc Chiến Tiền Ảo, thuộc thể loại tội phạm hình sự, được khởi động từ lúc đồng tiền bitcoin đang còn rất hot và tăng giá chóng mặt, đây có lẽ chính là nguồn cảm hứng cho John. Ngoài ra, phim còn có sự tham gia của dàn diễn viên tương đối chất lượng với một số gương mặt đáng chú ý như: Beau Knapp, Alexis Bledel, Luke Hemsworth, Kurt Russell, Jeremie Harris, Jill Hennessy, Vincent Kartheiser,… Nội dung phim xoay quanh nhân vật Caleb, một nhân viên ngân hàng trẻ đang làm việc tại Phố Wall. Sau khi bị giáng chức trở về quê nhà, anh bắt đầu tìm hiểu nhiều hơn về đồng tiền ảo và vô tình bị lôi kéo vào điều tra một mạng lưới rối rắm về tham nhũng và lừa đảo ở Upstate New York. Từ đây, cuộc sống của anh thay đổi chóng mặt, nó vừa có ảnh hưởng tích cực nhưng khiến anh rơi vào sự rối loạn cả về tâm lý lẫn công việc.</p>","tmdb":{"type":"movie","id":"567733","season":null,"vote_average":5.379,"vote_count":199},"modified":"2022-10-17T19:43:55.000Z","_image_preserved":true},{"id":"6276aedf3a2c0c6289bf1806","_id":"6276aedf3a2c0c6289bf1806","title":"Sau Thế Chiến","origin_name":"The Aftermath","slug":"sau-the-chien","year":2019,"type":"single","genre":[{"id":"620a220de0fc277084dfd16d","name":"Tình Cảm","slug":"tinh-cam"},{"id":"620a2238e0fc277084dfd291","name":"Tâm Lý","slug":"tam-ly"},{"id":"620a2253e0fc277084dfd339","name":"Chiến Tranh","slug":"chien-tranh"}],"country":[{"id":"620a231fe0fc277084dfd7ce","name":"Âu Mỹ","slug":"au-my"},{"id":"620a2370e0fc277084dfd91e","name":"Anh","slug":"anh"},{"id":"620e0e8fd9648f114cde77f7","name":"Đức","slug":"duc"}],"lang_key":"Vietsub","episode_current":"Full","quality":"HD","is_4k":false,"is_exclusive":false,"status":"completed","showtimes":"","chieurap":false,"sub_docquyen":false,"episodes":[{"server_name":"Vietsub #1","is_ai":false,"server_data":[{"n